module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

reg [size-1:0] mul_a_reg, mul_b_reg;
reg [size-1:0] temp [size-1:0];
reg [size-1:0] sum [size-1:0];

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_en_out <= 0;
        mul_out <= 0;
        mul_a_reg <= 0;
        mul_b_reg <= 0;
        temp <= 0;
        sum <= 0;
    end else begin
        if (mul_en_in) begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
        end
        mul_en_out <= mul_en_in;
        mul_out <= {sum[size-1], sum[size-2]};
        temp <= {temp[size-2:0], mul_a_reg & mul_b_reg};
        sum <= {sum[size-2:0], temp[size-1] + temp[size-2]};
    end
end

endmodule
